"use client"

import { useFinancial } from "@/hooks/useFinancial"
import { Navigation } from "@/components/navigation"
import { Card } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { LineChart, Line, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from "recharts"
import { Download } from "lucide-react"
import { AuthGuard } from "@/components/auth-guard"
import { useState, useEffect, useMemo } from "react" // Adicionado para controle de estado e performance

export default function ReportsPage() {
  const { data, loading } = useFinancial()
  const [mounted, setMounted] = useState(false)

  // Garante que o gráfico só renderize no cliente para evitar erros de hidratação
  useEffect(() => {
    setMounted(true)
  }, [])

  // Processa as transações reais para gerar os dados mensais
  const monthlyData = useMemo(() => {
    if (!data?.transactions || data.transactions.length === 0) return []

    const monthsMap: Record<string, { month: string; income: number; expenses: number; savings: number }> = {}
    
    // Nomes dos meses para exibição
    const monthNames = ["Jan", "Fev", "Mar", "Abr", "Mai", "Jun", "Jul", "Ago", "Set", "Out", "Nov", "Dez"]

    data.transactions.forEach((t) => {
      const date = new Date(t.date)
      const monthLabel = monthNames[date.getMonth()]
      
      if (!monthsMap[monthLabel]) {
        monthsMap[monthLabel] = { month: monthLabel, income: 0, expenses: 0, savings: 0 }
      }

      if (t.type === "income") {
        monthsMap[monthLabel].income += Number(t.amount)
      } else {
        monthsMap[monthLabel].expenses += Number(t.amount)
      }
      
      monthsMap[monthLabel].savings = monthsMap[monthLabel].income - monthsMap[monthLabel].expenses
    })

    // Retorna os dados ordenados cronologicamente (ajustar lógica de ordenação se necessário)
    return Object.values(monthsMap).reverse()
  }, [data?.transactions])

  const handleExportCSV = () => {
    const headers = ["Data", "Tipo", "Categoria", "Valor", "Descricao"]
    const rows =
      data?.transactions.map((t) => [
        new Date(t.date).toLocaleDateString(),
        t.type,
        t.category,
        t.amount,
        t.description,
      ]) || []

    const csv = [headers, ...rows].map((row) => row.join(",")).join("\n")
    const blob = new Blob([csv], { type: "text/csv" })
    const url = window.URL.createObjectURL(blob)
    const a = document.createElement("a")
    a.href = url
    a.download = "transacoes.csv"
    a.click()
  }

  if (loading) {
    return (
      <div className="flex h-screen items-center justify-center bg-background">
        <p>Carregando relatórios reais...</p>
      </div>
    )
  }

  return (
    <AuthGuard>
      <div className="flex h-screen bg-background">
        <Navigation />
        <main className="flex-1 overflow-auto">
          <div className="p-8">
            <div className="flex justify-between items-center mb-8">
              <div>
                <h2 className="text-3xl font-bold">Relatórios</h2>
                <p className="text-muted-foreground mt-1">Analise seus dados reais sincronizados</p>
              </div>
              <Button onClick={handleExportCSV} className="gap-2">
                <Download className="w-4 h-4" />
                Exportar CSV
              </Button>
            </div>

            <div className="grid grid-cols-1 gap-6">
              {/* Tendências Mensais baseadas no banco */}
              <Card className="p-6">
                <h3 className="text-lg font-semibold mb-4">Tendências Mensais</h3>
                <div className="h-[400px] w-full">
                  {mounted && (monthlyData.length > 0 ? (
                    <ResponsiveContainer width="100%" height="100%">
                      <LineChart data={monthlyData}>
                        <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" />
                        <XAxis dataKey="month" stroke="var(--muted-foreground)" />
                        <YAxis stroke="var(--muted-foreground)" />
                        <Tooltip contentStyle={{ backgroundColor: "var(--card)", border: "1px solid var(--border)" }} />
                        <Line type="monotone" dataKey="income" name="Receita" stroke="#10b981" strokeWidth={2} dot={{ r: 5 }} />
                        <Line type="monotone" dataKey="expenses" name="Despesa" stroke="#ef4444" strokeWidth={2} dot={{ r: 5 }} />
                        <Line type="monotone" dataKey="savings" name="Economia" stroke="#3b82f6" strokeWidth={2} dot={{ r: 5 }} />
                      </LineChart>
                    </ResponsiveContainer>
                  ) : (
                    <div className="flex h-full items-center justify-center text-muted-foreground border-2 border-dashed rounded-lg">
                      Dados insuficientes para gerar tendências.
                    </div>
                  ))}
                </div>
              </Card>

              {/* Comparação Mensal baseada no banco */}
              <Card className="p-6">
                <h3 className="text-lg font-semibold mb-4">Comparação Mensal</h3>
                <div className="h-[300px] w-full">
                  {mounted && (monthlyData.length > 0 ? (
                    <ResponsiveContainer width="100%" height="100%">
                      <BarChart data={monthlyData}>
                        <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" />
                        <XAxis dataKey="month" stroke="var(--muted-foreground)" />
                        <YAxis stroke="var(--muted-foreground)" />
                        <Tooltip contentStyle={{ backgroundColor: "var(--card)", border: "1px solid var(--border)" }} />
                        <Bar dataKey="income" name="Receita" fill="#10b981" radius={[4, 4, 0, 0]} />
                        <Bar dataKey="expenses" name="Despesa" fill="#ef4444" radius={[4, 4, 0, 0]} />
                        <Bar dataKey="savings" name="Economia" fill="#3b82f6" radius={[4, 4, 0, 0]} />
                      </BarChart>
                    </ResponsiveContainer>
                  ) : (
                    <div className="flex h-full items-center justify-center text-muted-foreground border-2 border-dashed rounded-lg">
                      Nenhuma transação registrada para comparação.
                    </div>
                  ))}
                </div>
              </Card>
            </div>
          </div>
        </main>
      </div>
    </AuthGuard>
  )
}